Javascript.miscCode:
	
		PayeeGrid.srcData = "/ds/EnterVariableData/PayeeBranch/payee_cols";
		PayeeGrid.rowXPath = "payee";
		PayeeGrid.keyXPath = "payeeid";
		PayeeGrid.columns = [{xpath: "detail"},{xpath: "name"},{xpath: "address"},{xpath: "reference"},{xpath: "bankname"},{xpath: "bankaddress"},{xpath: "sortcode"},{xpath: "accnumber"},{xpath: "amount"}];
			
		function FormEnabled(){}
		FormEnabled.dataBinding = "/ds/tmp/isFormEnabled";
		
		function PayeePopupBtn() {}
		PayeePopupBtn.actionBinding = function() 
		{	
			if ( PAYEE_COUNT == 4 )
			{
				alert("You can only create a maximum of 4 Payees.");
			}
			else
			{
				Services.dispatchEvent("Payee_Popup", PopupGUIAdaptor.EVENT_RAISE); 
				Services.setValue(FormEnabled.dataBinding, "true");
				Services.setValue(PayeeDetail.dataBinding, "");
				Services.setValue(PayeeName.dataBinding, "");
				Services.setValue(PayeeAdd1.dataBinding, "");
				Services.setValue(PayeeAdd2.dataBinding, "");
				Services.setValue(PayeeAdd3.dataBinding, "");
				Services.setValue(PayeeAdd4.dataBinding, "");
				Services.setValue(PayeeAdd5.dataBinding, "");
				Services.setValue(Postcode.dataBinding, "");
				Services.setValue(PayeeRef.dataBinding, "");
				Services.setValue(BankName.dataBinding, "");
				Services.setValue(BankAdd1.dataBinding, "");
				Services.setValue(BankAdd2.dataBinding, "");
				Services.setValue(BankAdd3.dataBinding, "");
				Services.setValue(BankAdd4.dataBinding, "");
				Services.setValue(BankAdd5.dataBinding, "");
				Services.setValue(BankPostcode.dataBinding, "");
				Services.setValue(Sortcode.dataBinding, "");
				Services.setValue(Accnumber.dataBinding, "");
				Services.setValue(PayeeAmount.dataBinding, "");			
			}
		}
	
		var PAYEE_COUNT = 0;
	
		function isPopupField(aField) {	
			var isPopupField = false;
			if (null != aField && null != aField.getDataBinding) {
				var db = aField.getDataBinding();
				var i=0;
				while (popupFieldsDBLen >= i && !isPopupField) {
					isPopupField = (db == popupFieldsDB[i]);
					i++; } }
			return isPopupField; }
	
		function PayeeAddBtn(){}
		PayeeAddBtn.actionBinding = function() {	
			var popupInvalidFields = new Array();
			invalidFields = FormController.getInstance().validateForm(false, false);
			if (invalidFields.length > 0) {	
				var invalidFieldsLen = invalidFields.length;
				for (var i=0; invalidFieldsLen >= i; i++) {
					var invalidField = invalidFields[i];
					if (isPopupField(invalidField)) {
						popupInvalidFields.push(invalidField); } } } 
			if (popupInvalidFields.length == 0) {	
				PAYEE_COUNT++;
				var payeeDOM= XML.createDOM();
							
			payeeDOM.loadXML("<payee><payeeid>" + PAYEE_COUNT +"</payeeid>"+
								"<detail></detail><name></name><address></address><reference></reference><bankname></bankname><bankaddress></bankaddress>"+
								"<sortcode></sortcode><accnumber></accnumber><amount></amount></payee>");
										
				var pbpcXPath = "/ds/EnterVariableData/PayeeBranch/payee_cols";			
				Services.addNode(payeeDOM, pbpcXPath);
				
				var pbpcXPath2 = pbpcXPath + "/payee[payeeid = " + PAYEE_COUNT +"]/";
				Services.setValue(pbpcXPath2 + "detail", Services.getValue(PayeeDetail.dataBinding));
				Services.setValue(pbpcXPath2 + "name", Services.getValue(PayeeName.dataBinding));
				Services.setValue(pbpcXPath2 + "address", Services.getValue(PayeeAdd1.dataBinding) + ", " +Services.getValue(PayeeAdd2.dataBinding) + " " + Services.getValue(PayeeAdd3.dataBinding) + " " + Services.getValue(PayeeAdd4.dataBinding) + " " + Services.getValue(PayeeAdd5.dataBinding) + " " + Services.getValue(Postcode.dataBinding));
				Services.setValue(pbpcXPath2 + "reference", Services.getValue(PayeeRef.dataBinding));
				Services.setValue(pbpcXPath2 + "bankname", Services.getValue(BankName.dataBinding));
				Services.setValue(pbpcXPath2 + "bankaddress", Services.getValue(BankAdd1.dataBinding) + ", " +Services.getValue(BankAdd2.dataBinding) + " " + Services.getValue(BankAdd3.dataBinding) + " " + Services.getValue(BankAdd4.dataBinding) + " " + Services.getValue(BankAdd5.dataBinding) + " " + Services.getValue(BankPostcode.dataBinding));
				Services.setValue(pbpcXPath2 + "sortcode", Services.getValue(Sortcode.dataBinding));
				Services.setValue(pbpcXPath2 + "accnumber", Services.getValue(Accnumber.dataBinding));
				Services.setValue(pbpcXPath2 + "amount", Services.getValue(PayeeAmount.dataBinding));
				
				Services.dispatchEvent("Payee_Popup", PopupGUIAdaptor.EVENT_LOWER);
			}
			else {
				alert("Form cannot be submitted as it has invalid value(s)"); }	}

		function PayeeCancelBtn(){}
		PayeeCancelBtn.actionBinding = function() {	
			var a = Services.getValue(PayeeGrid.dataBinding);
			if(a == "1") {
				Services.setValue(FormEnabled.dataBinding, "false"); }
			else {
				Services.setValue(FormEnabled.dataBinding, "true"); } 					
			FormController.getInstance().hideFormExtensionPopup("Payee_Popup");	}			
		
		function PayeeDetail(){}
		PayeeDetail.dataBinding 	= "/ds/var/app/WPData/payeedetails/payeeDetail";
		PayeeDetail.helpText 		= "Enter the payee details";
		PayeeDetail.mandatoryOn = [FormEnabled.dataBinding];
		PayeeDetail.maxLength = 260;
		PayeeDetail.isMandatory = function() { 
			return(Services.getValue(FormEnabled.dataBinding) == "true"); } 		
		
