		function Postcode(){}
		Postcode.dataBinding 	= "/ds/var/app/WPData/payeedetails/postcode";
		Postcode.helpText 		= "Enter payee postcode";
		Postcode.validateOn = [Postcode.dataBinding];
		Postcode.validate = function() {
			var value = Services.getValue(Postcode.dataBinding);
			if(!CaseManValidationHelper.validatePostCode(value)) {
				return ErrorCode.getErrorCode("CaseMan_invalidPostcodeFormat_Msg");	}
			return null; }		
		
