		function PayeeAmount(){}
		PayeeAmount.dataBinding = "/ds/var/app/WPData/payeedetails/payeeAmount";	
		PayeeAmount.helpText = "Enter payee amount";
		PayeeAmount.validateOn = [PayeeAmount.dataBinding];
		PayeeAmount.validate = function() {
			var value = Services.getValue(PayeeAmount.dataBinding);
			var max = 99999999.99;
			var err = validateCurrencyValue(value, max);
			if( null != err ) {
				return err; }
			return null; }	
		
		var popupFieldsDB = [	PayeeDetail.dataBinding, PayeeName.dataBinding,PayeeAdd1.dataBinding,PayeeAdd2.dataBinding,
